graphql.query:
query KonserTersedia {
  concerts(where: {available_quota: {_gt: 0}}, order_by: {event_date: asc}) {
    id
    name
    venue
    event_date
    price
    available_quota
    artist { name genre }
  }
}

query CariKonser($genre: String!, $keyword: String!) {
  concerts(where: {artist: {genre: {_eq: $genre}}, name: {_ilike: $keyword}}, order_by: {price: asc}) {
    id
    name
    price
    available_quota
    artist { name genre }
  }
}

query DetailKonser($id: Int!) {
  concerts_by_pk(id: $id) {
    id
    name
    venue
    event_date
    price
    total_quota
    available_quota
    artist { id name genre }
  }
}

query ArtisDenganKonser {
  artists(order_by: {name: asc}) {
    id
    name
    genre
    concerts(order_by: {event_date: asc}) {
      name
      event_date
      available_quota
    }
  }
}

query StatistikKatalog {
  concerts_aggregate {
    aggregate {
      count
      sum { available_quota }
    }
  }
}

mutation KurangiKuota($id: Int!) {
  update_concerts(where: {id: {_eq: $id}, available_quota: {_gt: 0}}, _inc: {available_quota: -1}) {
    affected_rows
    returning { id name available_quota }
  }
}

mutation TambahKonser($name: String!, $artist_id: Int!, $venue: String!, $event_date: timestamptz!, $price: numeric!, $quota: Int!) {
  insert_concerts_one(object: {name: $name, artist_id: $artist_id, venue: $venue, event_date: $event_date, price: $price, total_quota: $quota, available_quota: $quota}) {
    id
    name
  }
}

mutation SetKuota($id: Int!, $quota: Int!) {
  update_concerts(where: {id: {_eq: $id}}, _set: {available_quota: $quota}) {
    affected_rows
    returning { id name available_quota }
  }
}
